// index.js
require('dotenv').config();
const { ethers } = require('ethers');

class EthService {
    constructor() {
        // Ensure environment variables are set for security and configuration
        if (!process.env.ETH_PRIVATE_KEY || !process.env.ETH_PROVIDER_URL) {
            throw new Error("Missing ETH_PRIVATE_KEY or ETH_PROVIDER_URL in environment variables.");
        }

        // Initialize a provider to connect to the Ethereum network
        this.provider = new ethers.JsonRpcProvider(process.env.ETH_PROVIDER_URL);
        // Initialize a wallet with the private key for signing transactions
        this.wallet = new ethers.Wallet(process.env.ETH_PRIVATE_KEY, this.provider);

        console.log(`EthService initialized.`);
        console.log(`Connected with wallet address: ${this.wallet.address}`);
        console.log(`Using provider: ${process.env.ETH_PROVIDER_URL}`);
    }

    /**
     * Get the address of the configured wallet.
     * @returns {string} The wallet's Ethereum address.
     */
    async getWalletAddress() {
        return this.wallet.address;
    }

    /**
     * Get the balance of an Ethereum address.
     * If no address is provided, returns the balance of the configured wallet.
     * @param {string} [address] The Ethereum address to query.
     * @returns {Promise<string>} The balance in ETH.
     */
    async getBalance(address = this.wallet.address) {
        try {
            const balanceWei = await this.provider.getBalance(address);
            return ethers.formatEther(balanceWei); // Convert Wei to ETH
        } catch (error) {
            console.error(`Error getting balance for ${address}:`, error);
            throw error;
        }
    }

    /**
     * Sends Ether from the configured wallet to a recipient address.
     * @param {string} recipientAddress The address to send ETH to.
     * @param {string} amountEth The amount of ETH to send (e.g., "0.1").
     * @returns {Promise<ethers.TransactionReceipt>} The transaction receipt.
     */
    async sendEth(recipientAddress, amountEth) {
        try {
            const amountWei = ethers.parseEther(amountEth); // Convert ETH to Wei

            console.log(`Sending ${amountEth} ETH from ${this.wallet.address} to ${recipientAddress}...`);

            const tx = {
                to: recipientAddress,
                value: amountWei,
                // ethers.js automatically estimates gasLimit and gasPrice if not provided
            };

            const transactionResponse = await this.wallet.sendTransaction(tx);
            console.log('Transaction sent, hash:', transactionResponse.hash);

            const receipt = await transactionResponse.wait(); // Wait for transaction to be mined
            console.log('Transaction confirmed:', receipt);
            return receipt;
        } catch (error) {
            console.error(`Error sending ETH to ${recipientAddress}:`, error);
            throw error;
        }
    }

    /**
     * Interacts with a smart contract, sending a transaction (e.g., calling a state-changing function).
     * @param {string} contractAddress The address of the smart contract.
     * @param {string | ethers.InterfaceAbi} contractAbi The ABI of the smart contract. Can be a JSON string or parsed ABI array.
     * @param {string} functionName The name of the function to call (e.g., "store").
     * @param {Array<any>} args An array of arguments for the contract function.
     * @param {ethers.Overrides} [overrides={}] Optional transaction overrides (e.g., gasLimit, gasPrice, value).
     * @returns {Promise<ethers.TransactionReceipt>} The transaction receipt.
     */
    async sendContractTransaction(contractAddress, contractAbi, functionName, args = [], overrides = {}) {
        try {
            // Create a Contract instance connected to the wallet for signing transactions
            const contract = new ethers.Contract(contractAddress, contractAbi, this.wallet);

            console.log(`Calling contract function "${functionName}" on ${contractAddress} with args:`, args);

            // Dynamically call the contract function with arguments and overrides
            const transactionResponse = await contract[functionName](...args, overrides);
            console.log('Contract transaction sent, hash:', transactionResponse.hash);

            const receipt = await transactionResponse.wait(); // Wait for transaction to be mined
            console.log('Contract transaction confirmed:', receipt);
            return receipt;
        } catch (error) {
            console.error(`Error calling contract function "${functionName}" on ${contractAddress}:`, error);
            throw error;
        }
    }

    /**
     * Calls a read-only (view or pure) function on a smart contract.
     * This does not send a transaction and does not cost gas.
     * @param {string} contractAddress The address of the smart contract.
     * @param {string | ethers.InterfaceAbi} contractAbi The ABI of the smart contract.
     * @param {string} functionName The name of the view function to call (e.g., "retrieve").
     * @param {Array<any>} args An array of arguments for the contract function.
     * @returns {Promise<any>} The result of the contract call.
     */
    async callContractViewFunction(contractAddress, contractAbi, functionName, args = []) {
        try {
            // Create a Contract instance connected to the provider (no signing needed for view calls)
            const contract = new ethers.Contract(contractAddress, contractAbi, this.provider);

            console.log(`Calling contract view function "${functionName}" on ${contractAddress} with args:`, args);

            // Dynamically call the contract view function
            const result = await contract[functionName](...args);
            console.log('Contract view function result:', result);
            return result;
        } catch (error) {
            console.error(`Error calling contract view function "${functionName}" on ${contractAddress}:`, error);
            throw error;
        }
    }
}

